class Optimizer:
    def __init__(self, budget: int, dim: int, cont_dim: int):
        self.budget = budget
        self.dim = dim
        self.cont_dim = cont_dim
        self.cat_dim = dim - cont_dim

    def adaptive_differential_evolution(self, func, init_pop=None):
        if init_pop is None:
            init_pop = np.random.rand(10, self.dim) * 2 - 1
        bounds = [(-1, 1)] * self.cont_dim + [(0, len(glass_ids) - 1)] * self.cat_dim

        def de_func(x):
            return func(np.array([x[i] if i < self.cont_dim else int(x[i]) for i in range(self.dim)]))

        F = np.random.uniform(0.5, 1.0)
        CR = np.random.uniform(0.7, 0.9)

        best_f = float('inf')
        best_x = None

        for _ in range(self.budget // 10):
            indices = np.arange(init_pop.shape[0])
            np.random.shuffle(indices)

            for i in indices:
                a, b, c = np.random.choice(indices, 3, replace=False)
                while b == i or c == i:
                    b, c = np.random.choice(indices, 2, replace=False)

                mutant = init_pop[a] + F * (init_pop[b] - init_pop[c])
                mutant[:self.cont_dim] = np.clip(mutant[:self.cont_dim], bounds[0][0], bounds[0][1])

                trial = np.where(np.random.rand(self.dim) < CR, mutant, init_pop[i])

                if de_func(trial) < de_func(init_pop[i]):
                    init_pop[i] = trial
                    if de_func(trial) < best_f:
                        best_f, best_x = de_func(trial), trial

        return best_f, np.array([best_x[i] if i < self.cont_dim else int(best_x[i]) for i in range(self.dim)])

